// Pull both ensures into the proof context so the two `forall`-bearing
// `valid()` triggers and the `update`-equality facts line up.
assert(post1_self_.valid());
assert(post1_self_@ == pre_self_@.update(i as int, k));
assert(post2_self_.valid());
assert(post2_self_@ == pre_self_@.update(i as int, k));

// Both views are the same Seq, so they are equal by transitivity.
assert(post1_self_@ == post2_self_@);

// Sequence extensionality lifts the view equality for the determinism check.
assert(post1_self_@ =~= post2_self_@);
